// Make sure we're in WordPress context
if ( !defined( 'ABSPATH' ) ) {
    die;
}

add_action('init', 'display_user_profile');
function display_user_profile() {
    global $wpdb;
    
    $table = $wpdb->prefix . "custom_users";  // replace with your actual custom users table name
    $userId = intval($_GET['user_id']);        // get user id from URL parameter
  
    if (isset($userId)) {
        $sql = $wpdb->prepare("SELECT * FROM $table WHERE ID = %d", $userId);  // prepare SQL query with sanitization
        $result = $wpdb->get_results($sql, ARRAY_A);   // execute the query and store results in an associative array
        
        if (count($result) > 0) {
            echo "<h2>User Profile Information:</h2>";
            echo 'Name: ' . $result[0]['name'] . "<br />";  // access user name from result set
            echo 'Email: ' . $result[0]['email'] . "<br />";   // access user email from result set
        } else {
            echo "User not found.";
        }
    }
}